http:request.http:query-params:
#[{
            latitude: vars.customerLat,
            longitude: vars.customerLon,
            radius: 5,
            status: "ACTIVE"
          }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
payload.outages map {
  outageId: $.id,
  area: {
    description: $.area.description,
    coordinates: {
      center: {
        latitude: $.area.center.lat,
        longitude: $.area.center.lon
      },
      radius: $.area.radius
    }
  },
  status: $.status,
  customersAffected: $.customers_affected,
  estimatedRestoration: $.estimated_restoration as DateTime,
  cause: $.cause,
  updates: $.updates map {
    timestamp: $.timestamp as DateTime,
    message: $.message
  }
}

