%dw 2.0
output application/json
---
{
  outageId: payload.id,
  area: {
    description: payload.area.description,
    coordinates: {
      center: {
        latitude: payload.area.center.lat,
        longitude: payload.area.center.lon
      },
      radius: payload.area.radius
    }
  },
  status: payload.status,
  customersAffected: payload.customers_affected,
  estimatedRestoration: payload.estimated_restoration as DateTime,
  cause: payload.cause,
  updates: payload.updates map {
    timestamp: $.timestamp as DateTime,
    message: $.message
  },
  crews: payload.crews map {
    id: $.id,
    status: $.status,
    estimatedArrival: $.estimated_arrival as DateTime,
    location: {
      latitude: $.location.lat,
      longitude: $.location.lon
    }
  },
  affectedInfrastructure: payload.infrastructure map {
    type: $.type,
    id: $.id,
    status: $.status
  }
}
